const { app, BrowserWindow } = require('electron');
const path = require('path');
const { fork } = require('child_process');

let mainWindow;
let serverProcess;

function createWindow() {
  // Cria a janela do navegador.
  mainWindow = new BrowserWindow({
    width: 1280,
    height: 800,
    title: "SisFila - Gestão de Atendimento",
    autoHideMenuBar: true, // Esconde o menu File/Edit/etc para parecer um app nativo
    backgroundColor: '#0f172a',
    webPreferences: {
      nodeIntegration: false,
      contextIsolation: true,
    }
  });

  // Inicia o processo do servidor Node.js (server.js)
  // Usamos fork para que o servidor rode em uma thread separada e não trave a interface
  const serverPath = path.join(__dirname, 'server.js');

  serverProcess = fork(serverPath, [], {
    env: { 
      ...process.env, 
      ELECTRON_RUN: 'true',
      NODE_ENV: 'production'
    }
  });

  // Aguarda um pequeno tempo para o servidor subir antes de carregar a URL
  // No mundo ideal, usaríamos uma verificação de porta, mas 1.5s é seguro para SQLite
  setTimeout(() => {
    mainWindow.loadURL('http://localhost:3000');
  }, 2000);

  // Tratamento quando a janela é fechada
  mainWindow.on('closed', function () {
    mainWindow = null;
  });

  // Caso o servidor falhe ou feche, podemos monitorar aqui
  serverProcess.on('exit', (code) => {
    console.log(`Servidor encerrado com código: ${code}`);
  });
}

// Este método será chamado quando o Electron terminar a inicialização
app.on('ready', createWindow);

// Encerra o servidor e o app quando todas as janelas forem fechadas
app.on('window-all-closed', function () {
  if (process.platform !== 'darwin') {
    if (serverProcess) {
      serverProcess.kill(); // Mata o processo do servidor Node.js
    }
    app.quit();
  }
});

app.on('activate', function () {
  if (mainWindow === null) {
    createWindow();
  }
});

