  const socketRef = useRef<Socket | null>(null);
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  useEffect(() => {
    document.title = currentUser ? `SisFila - ${currentUser.name}` : 'SisFila - Login';
  }, [currentUser]);

  useEffect(() => {
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    const storedServerUrl = localStorage.getItem('SISFILA_SERVER_URL');
    const apiBase = storedServerUrl ? storedServerUrl : '';

    const fetchBaseData = () => {
        fetch(`${apiBase}/api/license`).then(res => res.json()).then(setSystemInfo).catch(() => {});
        fetch(`${apiBase}/api/printer-config`).then(res => res.json()).then(setPrinterConfig).catch(() => {});
    };

    fetchBaseData();

    const params = new URLSearchParams(window.location.search);
    if (params.get('view') === 'tv') setIsTvMode(true);

    const socketUrl = storedServerUrl || (window.location.hostname === 'localhost' ? 'http://localhost:3000' : undefined);
    const socket = io(socketUrl, { reconnectionAttempts: 5 });

    socket.on('connect', () => {
      setServerMode(true);
      setConnectionStatus('connected');
    });

    socket.on('disconnect', () => {
      setServerMode(false);
      setConnectionStatus('offline');
    });

    socket.on('initial-data', (data: any) => {
      setState(prev => ({ ...prev, ...data }));
    });

    socket.on('sync-update', (event: any) => {
      if (event.type === 'TICKETS') {
        setState(prev => {
          const isArray = Array.isArray(event.data);
          const newTickets = [...prev.tickets];
          const incoming = isArray ? event.data : [event.data];

          incoming.forEach((t: Ticket) => {
            const idx = newTickets.findIndex(ot => ot.id === t.id);
            if (idx >= 0) newTickets[idx] = t;
            else newTickets.push(t);
          });
          return { ...prev, tickets: newTickets };
        });
      }
    });

    socketRef.current = socket;
    return () => { socket.disconnect(); };
  }, []);

