    const apiBase = storedServerUrl || '';

    fetch(`${apiBase}/api/license`).then(res => res.json()).then(setSystemInfo).catch(() => {});
    fetch(`${apiBase}/api/printer-config`).then(res => res.json()).then(setPrinterConfig).catch(() => {});

    const params = new URLSearchParams(window.location.search);
    if (params.get('view') === 'tv') setIsTvMode(true);

    const socketUrl = storedServerUrl || (window.location.hostname === 'localhost' ? 'http://localhost:3000' : undefined);
    const socket = io(socketUrl, { reconnectionAttempts: 10 });

    socket.on('connect', () => setConnectionStatus('connected'));
    socket.on('disconnect', () => setConnectionStatus('offline'));
    socket.on('initial-data', (data: any) => setState(prev => ({ ...prev, ...data })));

    socket.on('sync-update', (event: any) => {
      if (event.type === 'TICKETS') {
        setState(prev => {
          const newTickets = [...prev.tickets];
          const incoming = Array.isArray(event.data) ? event.data : [event.data];
          incoming.forEach((t: Ticket) => {
            const idx = newTickets.findIndex(ot => ot.id === t.id);
            if (idx >= 0) newTickets[idx] = t;
            else newTickets.push(t);
          });
          return { ...prev, tickets: newTickets };
        });
      } else if (event.type === 'SERVICES') {
        setState(prev => ({ ...prev, services: event.data }));
      } else if (event.type === 'USERS') {
        setState(prev => ({ ...prev, users: event.data }));
      }
    });

    socketRef.current = socket;
    return () => { socket.disconnect(); };
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = state.users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user && user.active) {
      setCurrentUser(user);
      setState(p => ({ ...p, view: 'home' }));
    } else {
      setLoginError('Acesso inválido ou conta inativa.');
    }
  };

  const issueTicket = (serviceId: string, priority: PriorityType) => {
    const service = state.services.find(s => s.id === serviceId);
    if (!service) return;

    const displayId = `${service.name.charAt(0)}${priority === 'Prioritário' ? 'P' : 'N'}${Math.floor(Math.random() * 900 + 100)}`;
    const newTicket: Ticket = {
      id: uuidv4(),
      displayId,
      serviceId,
      serviceName: service.name,
      priority,
      status: TicketStatus.WAITING,
      createdAt: Date.now()
    };

    setState(prev => ({ ...prev, tickets: [...prev.tickets, newTicket] }));
    socketRef.current?.emit('update-tickets', [newTicket]);
    setLastIssuedTicket(newTicket);
    setTimeout(() => setLastIssuedTicket(null), 5000);
  };

  if (isTvMode) return <TvView tickets={state.tickets} systemInfo={systemInfo} />;

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950 p-6 font-sans">
        <div className="w-full max-w-[400px] bg-slate-900/40 backdrop-blur-2xl border border-white/5 rounded-[2.5rem] p-10 shadow-2xl animate-fade-in relative overflow-hidden">
          <div className="absolute -top-20 -right-20 w-40 h-40 bg-indigo-600/20 blur-3xl rounded-full"></div>

          <div className="text-center mb-10 relative z-10">
            <div className="w-20 h-20 bg-gradient-to-tr from-indigo-600 to-violet-500 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-indigo-500/20 rotate-3">
              <Layers className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-white tracking-tighter uppercase">SisFila <span className="text-indigo-500">3.0</span></h1>
            <p className="text-slate-500 text-sm font-medium mt-2">Inteligência em Atendimento</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5 relative z-10">
            {loginError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-400 text-xs rounded-2xl flex items-center gap-3 animate-pulse">
                <AlertCircle size={16}/> {loginError}
              </div>
            )}

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-4">Usuário</label>
              <div className="bg-white/5 border border-white/10 rounded-2xl px-5 py-4 flex items-center gap-4 focus-within:border-indigo-500/50 transition-all focus-within:bg-white/10">
                <UserIcon size={20} className="text-slate-500" />
                <input value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="bg-transparent border-none outline-none text-white w-full text-sm font-medium" placeholder="Seu login" />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-4">Senha</label>
              <div className="bg-white/5 border border-white/10 rounded-2xl px-5 py-4 flex items-center gap-4 focus-within:border-indigo-500/50 transition-all focus-within:bg-white/10">
                <Lock size={20} className="text-slate-500" />
                <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="bg-transparent border-none outline-none text-white w-full text-sm font-medium" placeholder="••••••••" />
              </div>
            </div>

            <button type="submit" className="w-full bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 text-white font-black py-4 rounded-2xl shadow-xl shadow-indigo-500/10 transition-all active:scale-95 flex items-center justify-center gap-3 mt-4">
              <LogIn size={20} /> ENTRAR NO SISTEMA
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans">
      {/* Sidebar */}
      <aside className="w-72 border-r border-white/5 flex flex-col p-6 bg-slate-900/30 backdrop-blur-3xl">
        <div className="flex items-center gap-3 px-2 mb-12">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Layers size={24} className="text-white" />
          </div>
          <div>
            <span className="font-black text-white text-xl tracking-tighter">SISFILA</span>
            <div className="flex items-center gap-1">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">v3.0 Premium</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 space-y-3">
          <MenuButton active={state.view === 'home'} onClick={() => setState(p => ({ ...p, view: 'home' }))} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <MenuButton active={state.view === 'totem'} onClick={() => setState(p => ({ ...p, view: 'totem' }))} icon={<Monitor size={20}/>} label="Terminal Totem" />
          <MenuButton active={state.view === 'attendant'} onClick={() => setState(p => ({ ...p, view: 'attendant' }))} icon={<Users size={20}/>} label="Atendimento" />
          <MenuButton active={state.view === 'reports'} onClick={() => setState(p => ({ ...p, view: 'reports' }))} icon={<FileText size={20}/>} label="Relatórios IA" />
          {currentUser.role === 'admin' && <MenuButton active={state.view === 'settings'} onClick={() => setState(p => ({ ...p, view: 'settings' }))} icon={<Settings size={20}/>} label="Ajustes Sistema" />}
        </nav>

        <div className="mt-auto p-5 bg-white/5 rounded-3xl border border-white/10">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-tr from-indigo-500 to-purple-500 flex items-center justify-center text-white font-black text-lg shadow-lg">{currentUser.name.charAt(0)}</div>
            <div className="overflow-hidden">
              <p className="text-sm font-black text-white truncate">{currentUser.name}</p>
              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest">{currentUser.role === 'admin' ? 'Administrador' : 'Atendente'}</p>
            </div>
          </div>
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center justify-center gap-2 py-3 text-xs font-black text-red-400 hover:bg-red-500/10 rounded-xl transition-all border border-transparent hover:border-red-500/20">
            <LogOut size={16} /> ENCERRAR SESSÃO
          </button>
        </div>
      </aside>

      {/* Main Content */}
