                     <p className="text-slate-500 font-medium">Visão geral do tráfego de hoje em tempo real.</p>
                   </div>
                   <div className="text-right">
                     <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1">Status do Sistema</p>
                     <p className="text-sm font-bold text-white flex items-center gap-2 justify-end">
                       <Zap size={14} className="text-yellow-500"/> Operacional
                     </p>
                   </div>
