import { GoogleGenAI } from "@google/genai";
import { Ticket, TicketStatus } from "../types";

const apiKey = process.env.API_KEY || ""; 
let ai: GoogleGenAI | null = null;

if (apiKey) {
    ai = new GoogleGenAI({ apiKey });
}

const MODEL_NAME = 'gemini-3-flash-preview';

export async function generateQueueReport(tickets: Ticket[], filterContext: string = ""): Promise<string> {
  if (!navigator.onLine) {
    return "⚠️ **Modo Offline**\n\nConecte-se à internet para que o Gemini analise seus dados.";
  }

  if (!ai) {
    return "⚠️ **Erro de Configuração**\n\nChave de IA não encontrada no servidor.";
  }

  const processedTickets = tickets.filter(t => t.status !== TicketStatus.WAITING);

  if (processedTickets.length === 0) {
    return "Não há dados suficientes para uma análise inteligente.";
  }

  const dataSummary = JSON.stringify(processedTickets.map(t => ({
    id: t.displayId,
    serv: t.serviceName,
    prior: t.priority,
    st: t.status,
    espera_seg: t.calledAt ? (t.calledAt - t.createdAt) / 1000 : 0,
    atend_seg: (t.finishedAt && t.startedAt) ? (t.finishedAt - t.startedAt) / 1000 : 0,
    hora: t.calledAt ? new Date(t.calledAt).getHours() : null
  })));

  const prompt = `
    Como um Analista Sênior de Operações, examine estes dados de atendimento do SisFila:

    Contexto: ${filterContext}
    Dados JSON: ${dataSummary}

    Gere um relatório executivo em Markdown com:
    1. **Insights Críticos**: Identifique os horários de pico e serviços que mais demoram.
    2. **Métricas de Ouro**: Tempo médio de espera e eficiência de atendimento (senhas/hora).
    3. **Sentimento de Operação**: Com base nos tempos, como está a percepção de qualidade do cliente?
    4. **Sugestão Gemini**: Como otimizar a escala de atendentes para amanhã?

    Use um tom profissional, direto e otimista. Utilize tabelas Markdown onde necessário.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "Erro na geração do texto.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Ocorreu um erro ao processar a inteligência artificial.";
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { v4 as uuidv4 } from 'uuid';
import { Ticket, TicketStatus, AppState, PriorityType, User, Service, SystemInfo, PrinterConfig } from './types';
import { TotemView } from './components/TotemView';
import { TvView } from './components/TvView';
import { AttendantView } from './components/AttendantView';
import { ReportsView } from './components/ReportsView';
import { SettingsView } from './components/SettingsView';
import { 
  Monitor, Tv, Users, FileText, Layers, Settings, ExternalLink, 
  Sun, Moon, Wifi, WifiOff, Download, LogOut, Lock, LogIn, 
  AlertCircle, User as UserIcon, ShieldAlert, RefreshCw, LayoutDashboard,
  Clock, CheckCircle2, TrendingUp, Sparkles, Zap, Menu, ChevronLeft, Maximize2
} from 'lucide-react';
import { io, Socket } from 'socket.io-client';

const DEFAULT_STATE: AppState = {
  tickets: [],
  services: [],
  users: [],
  view: 'home'
};

function App() {
  const [isTvMode, setIsTvMode] = useState(false);
  const [sidebarHidden, setSidebarHidden] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<'connecting' | 'connected' | 'offline'>('connecting');

  const [state, setState] = useState<AppState>(DEFAULT_STATE);
  const [lastIssuedTicket, setLastIssuedTicket] = useState<Ticket | null>(null);
  const [systemInfo, setSystemInfo] = useState<SystemInfo | null>(null);
  const [printerConfig, setPrinterConfig] = useState<PrinterConfig | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const [loginUsername, setLoginUsername] = useState('');
  const [loginPassword, setLoginPassword] = useState('');
  const [loginError, setLoginError] = useState('');

  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    const storedServerUrl = localStorage.getItem('SISFILA_SERVER_URL');
    const apiBase = storedServerUrl || '';

    fetch(`${apiBase}/api/license`).then(res => res.json()).then(setSystemInfo).catch(() => {});
    fetch(`${apiBase}/api/printer-config`).then(res => res.json()).then(setPrinterConfig).catch(() => {});

    const params = new URLSearchParams(window.location.search);
    if (params.get('view') === 'tv') setIsTvMode(true);

    const socketUrl = storedServerUrl || (window.location.hostname === 'localhost' ? 'http://localhost:3000' : undefined);
    const socket = io(socketUrl, { reconnectionAttempts: 10 });

    socket.on('connect', () => setConnectionStatus('connected'));
    socket.on('disconnect', () => setConnectionStatus('offline'));
    socket.on('initial-data', (data: any) => setState(prev => ({ ...prev, ...data })));

    socket.on('sync-update', (event: any) => {
      if (event.type === 'TICKETS') {
        setState(prev => {
          const newTickets = [...prev.tickets];
          const incoming = Array.isArray(event.data) ? event.data : [event.data];
          incoming.forEach((t: Ticket) => {
            const idx = newTickets.findIndex(ot => ot.id === t.id);
            if (idx >= 0) newTickets[idx] = t;
            else newTickets.push(t);
          });
          return { ...prev, tickets: newTickets };
        });
      } else if (event.type === 'SERVICES') {
        setState(prev => ({ ...prev, services: event.data }));
      } else if (event.type === 'USERS') {
        setState(prev => ({ ...prev, users: event.data }));
      }
    });

    socketRef.current = socket;
    return () => { socket.disconnect(); };
  }, []);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const user = state.users.find(u => u.username === loginUsername && u.password === loginPassword);
    if (user && user.active) {
      setCurrentUser(user);
      setState(p => ({ ...p, view: 'home' }));
    } else {
      setLoginError('Acesso inválido ou conta inativa.');
    }
  };

  const issueTicket = (serviceId: string, priority: PriorityType) => {
    const service = state.services.find(s => s.id === serviceId);
    if (!service) return;

    const displayId = `${service.name.charAt(0)}${priority === 'Prioritário' ? 'P' : 'N'}${Math.floor(Math.random() * 900 + 100)}`;
    const newTicket: Ticket = {
      id: uuidv4(),
      displayId,
      serviceId,
      serviceName: service.name,
      priority,
      status: TicketStatus.WAITING,
      createdAt: Date.now()
    };

    setState(prev => ({ ...prev, tickets: [...prev.tickets, newTicket] }));
    socketRef.current?.emit('update-tickets', [newTicket]);
    setLastIssuedTicket(newTicket);
    setTimeout(() => setLastIssuedTicket(null), 5000);
  };

  if (isTvMode) return <TvView tickets={state.tickets} systemInfo={systemInfo} />;

  if (!currentUser) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-slate-950 p-6 font-sans">
        <div className="w-full max-w-[400px] bg-slate-900/40 backdrop-blur-2xl border border-white/5 rounded-[2.5rem] p-10 shadow-2xl animate-fade-in relative overflow-hidden">
          <div className="absolute -top-20 -right-20 w-40 h-40 bg-indigo-600/20 blur-3xl rounded-full"></div>

          <div className="text-center mb-10 relative z-10">
            <div className="w-20 h-20 bg-gradient-to-tr from-indigo-600 to-violet-500 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-indigo-500/20 rotate-3">
              <Layers className="text-white" size={40} />
            </div>
            <h1 className="text-3xl font-black text-white tracking-tighter uppercase">SisFila <span className="text-indigo-500">3.0</span></h1>
            <p className="text-slate-500 text-sm font-medium mt-2">Inteligência em Atendimento</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-5 relative z-10">
            {loginError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-400 text-xs rounded-2xl flex items-center gap-3 animate-pulse">
                <AlertCircle size={16}/> {loginError}
              </div>
            )}

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-4">Usuário</label>
              <div className="bg-white/5 border border-white/10 rounded-2xl px-5 py-4 flex items-center gap-4 focus-within:border-indigo-500/50 transition-all focus-within:bg-white/10">
                <UserIcon size={20} className="text-slate-500" />
                <input value={loginUsername} onChange={e => setLoginUsername(e.target.value)} className="bg-transparent border-none outline-none text-white w-full text-sm font-medium" placeholder="Seu login" />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-500 uppercase tracking-widest ml-4">Senha</label>
              <div className="bg-white/5 border border-white/10 rounded-2xl px-5 py-4 flex items-center gap-4 focus-within:border-indigo-500/50 transition-all focus-within:bg-white/10">
                <Lock size={20} className="text-slate-500" />
                <input type="password" value={loginPassword} onChange={e => setLoginPassword(e.target.value)} className="bg-transparent border-none outline-none text-white w-full text-sm font-medium" placeholder="••••••••" />
              </div>
            </div>

            <button type="submit" className="w-full bg-gradient-to-r from-indigo-600 to-violet-600 hover:from-indigo-500 hover:to-violet-500 text-white font-black py-4 rounded-2xl shadow-xl shadow-indigo-500/10 transition-all active:scale-95 flex items-center justify-center gap-3 mt-4">
              <LogIn size={20} /> ENTRAR NO SISTEMA
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans">
      {/* Sidebar */}
      <aside className={`${sidebarHidden ? 'w-0 opacity-0 pointer-events-none' : 'w-72 opacity-100'} border-r border-white/5 flex flex-col p-6 bg-slate-900/30 backdrop-blur-3xl transition-all duration-500 ease-in-out relative overflow-hidden shrink-0`}>
        <div className="flex items-center gap-3 px-2 mb-12">
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
            <Layers size={24} className="text-white" />
          </div>
          <div className="whitespace-nowrap">
            <span className="font-black text-white text-xl tracking-tighter">SISFILA</span>
            <div className="flex items-center gap-1">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
              <span className="text-[8px] font-black text-slate-500 uppercase tracking-widest">v3.0 Premium</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 space-y-3">
          <MenuButton active={state.view === 'home'} onClick={() => setState(p => ({ ...p, view: 'home' }))} icon={<LayoutDashboard size={20}/>} label="Dashboard" />
          <MenuButton active={state.view === 'totem'} onClick={() => setState(p => ({ ...p, view: 'totem' }))} icon={<Monitor size={20}/>} label="Terminal Totem" />
          <MenuButton active={state.view === 'attendant'} onClick={() => setState(p => ({ ...p, view: 'attendant' }))} icon={<Users size={20}/>} label="Atendimento" />
          <MenuButton active={state.view === 'reports'} onClick={() => setState(p => ({ ...p, view: 'reports' }))} icon={<FileText size={20}/>} label="Relatórios IA" />
          {currentUser.role === 'admin' && <MenuButton active={state.view === 'settings'} onClick={() => setState(p => ({ ...p, view: 'settings' }))} icon={<Settings size={20}/>} label="Ajustes Sistema" />}
        </nav>

        <div className="mt-auto p-5 bg-white/5 rounded-3xl border border-white/10">
          <div className="flex items-center gap-4 mb-6">
            <div className="w-12 h-12 rounded-2xl bg-gradient-to-tr from-indigo-500 to-purple-500 flex items-center justify-center text-white font-black text-lg shadow-lg">{currentUser.name.charAt(0)}</div>
            <div className="overflow-hidden">
              <p className="text-sm font-black text-white truncate">{currentUser.name}</p>
              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest">{currentUser.role === 'admin' ? 'Administrador' : 'Atendente'}</p>
            </div>
          </div>
          <button onClick={() => setCurrentUser(null)} className="w-full flex items-center justify-center gap-2 py-3 text-xs font-black text-red-400 hover:bg-red-500/10 rounded-xl transition-all border border-transparent hover:border-red-500/20">
            <LogOut size={16} /> ENCERRAR SESSÃO
          </button>
        </div>

        {/* Manual Hide Toggle */}
        <button 
          onClick={() => setSidebarHidden(true)} 
          className="absolute top-1/2 -right-1 translate-x-1/2 p-2 bg-indigo-600 rounded-full text-white shadow-xl hover:bg-indigo-500 transition-colors z-50 group no-print"
        >
          <ChevronLeft size={16} />
        </button>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col overflow-hidden relative">
        {/* Floating Restore Button */}
        {sidebarHidden && (
          <button 
            onClick={() => setSidebarHidden(false)}
            className="fixed bottom-8 left-8 z-[100] p-4 bg-slate-900/80 backdrop-blur-xl border border-white/10 rounded-[1.5rem] text-indigo-400 hover:text-white transition-all shadow-2xl hover:scale-110 active:scale-95 group no-print"
          >
            <Menu size={24} />
            <span className="absolute left-full ml-4 px-3 py-1 bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none shadow-lg">Mostrar Menu</span>
          </button>
        )}

        <header className="h-20 border-b border-white/5 flex items-center justify-between px-10 bg-slate-950/40 backdrop-blur-md z-20 shrink-0">
          <div className="flex items-center gap-6">
             <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest flex items-center gap-2 border ${connectionStatus === 'connected' ? 'bg-emerald-500/5 text-emerald-500 border-emerald-500/20' : 'bg-red-500/5 text-red-500 border-red-500/20'}`}>
               <div className={`w-2 h-2 rounded-full ${connectionStatus === 'connected' ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
               {connectionStatus === 'connected' ? 'Link Estável' : 'Sem Conexão'}
             </div>
             {currentUser.deskNumber && (
               <div className="text-xs font-bold text-slate-500">Mesa <span className="text-white bg-slate-800 px-2 py-1 rounded-lg ml-1">{currentUser.deskNumber}</span></div>
             )}
          </div>
          <div className="flex items-center gap-4">
            {state.view === 'totem' && !sidebarHidden && (
              <button 
                onClick={() => setSidebarHidden(true)}
                className="flex items-center gap-2 px-5 py-2.5 bg-slate-800 hover:bg-slate-700 text-white rounded-xl text-[10px] font-black tracking-widest uppercase transition-all"
              >
                <Maximize2 size={14}/> Modo Imersivo
              </button>
            )}
            <button onClick={() => window.open(window.location.href + '?view=tv', '_blank')} className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl text-[10px] font-black tracking-widest uppercase transition-all shadow-lg shadow-indigo-600/20">
              <ExternalLink size={14}/> Ver Monitor TV
            </button>
          </div>
        </header>

        <div className="flex-1 overflow-y-auto p-10 bg-slate-950/20">
           {state.view === 'home' && (
             <div className="max-w-6xl mx-auto space-y-10 animate-fade-in">
                <div className="flex items-end justify-between">
                   <div>
                     <h2 className="text-4xl font-black text-white tracking-tighter">Dashboard <span className="text-indigo-500">Live</span></h2>
                     <p className="text-slate-500 font-medium">Visão geral do tráfego de hoje em tempo real.</p>
                   </div>
                   <div className="text-right">
                     <p className="text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1">Status do Sistema</p>
                     <p className="text-sm font-bold text-white flex items-center gap-2 justify-end">
                       <Zap size={14} className="text-yellow-500"/> Operacional
                     </p>
                   </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  <StatCard icon={<Users size={24} className="text-blue-500" />} label="Na Fila" value={state.tickets.filter(t => t.status === TicketStatus.WAITING).length} trend="+2 desde 10min" />
                  <StatCard icon={<CheckCircle2 size={24} className="text-emerald-500" />} label="Finalizados" value={state.tickets.filter(t => t.status === TicketStatus.FINISHED).length} trend="Meta: 50/dia" />
                  <StatCard icon={<Clock size={24} className="text-purple-500" />} label="T. M. Espera" value="8 min" trend="-15% melhoria" />
                  <StatCard icon={<TrendingUp size={24} className="text-amber-500" />} label="Capacidade" value="92%" trend="Alta demanda" />
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                   <div className="lg:col-span-2 space-y-6">
                      <div className="bg-slate-900/40 border border-white/5 rounded-[2rem] p-8 backdrop-blur-sm">
                        <div className="flex items-center justify-between mb-8">
                          <h3 className="font-black text-white flex items-center gap-3 uppercase text-xs tracking-widest"><Sparkles size={18} className="text-indigo-500"/> Atalhos Rápidos</h3>
                        </div>
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                          <QuickAction icon={<Monitor size={24}/>} label="Configurar Totem" desc="Gerenciar terminais" color="bg-blue-600" onClick={() => setState(p => ({...p, view: 'totem'}))} />
                          <QuickAction icon={<Users size={24}/>} label="Painel Atendimento" desc="Chamar próxima senha" color="bg-indigo-600" onClick={() => setState(p => ({...p, view: 'attendant'}))} />
                          <QuickAction icon={<FileText size={24}/>} label="Relatórios Gemini" desc="Insights com IA" color="bg-emerald-600" onClick={() => setState(p => ({...p, view: 'reports'}))} />
                          <QuickAction icon={<Settings size={24}/>} label="Ajustes de Mesa" desc="Sua configuração" color="bg-purple-600" onClick={() => setState(p => ({...p, view: 'settings'}))} />
                        </div>
                      </div>
                   </div>

                   <div className="bg-slate-900/40 border border-white/5 rounded-[2rem] p-8 backdrop-blur-sm flex flex-col">
                      <h3 className="font-black text-white mb-6 uppercase text-xs tracking-widest">Atividade Recente</h3>
                      <div className="space-y-4 overflow-y-auto flex-1 pr-2 custom-scrollbar">
                        {state.tickets.slice(-6).reverse().map(t => (
                          <div key={t.id} className="flex items-center justify-between p-4 bg-white/5 rounded-2xl border border-white/5 group hover:bg-white/10 transition-all">
                            <div>
                              <span className="font-black text-white text-xl tracking-tighter">{t.displayId}</span>
                              <p className="text-[9px] text-slate-500 uppercase font-black tracking-widest mt-0.5">{t.serviceName}</p>
                            </div>
                            <div className="text-right">
                              <span className={`px-2.5 py-1 rounded-lg text-[8px] font-black uppercase tracking-tighter ${t.status === 'waiting' ? 'bg-blue-500/10 text-blue-400' : 'bg-emerald-500/10 text-emerald-400'}`}>
                                {t.status === 'waiting' ? 'Aguardando' : 'Processado'}
                              </span>
                            </div>
                          </div>
                        ))}
                      </div>
                   </div>
                </div>
             </div>
           )}

           {state.view === 'totem' && <TotemView services={state.services} onIssueTicket={issueTicket} lastTicket={lastIssuedTicket} printerConfig={printerConfig} />}
           {state.view === 'attendant' && (
             <AttendantView 
                tickets={state.tickets} 
                services={state.services} 
                currentUser={currentUser}
                onCallNext={(sid, name, desk) => socketRef.current?.emit('update-tickets', [{ ...state.tickets.find(t => t.id === sid), status: TicketStatus.CALLED, attendantName: name, deskNumber: desk, calledAt: Date.now() }])}
                onRecall={(id) => socketRef.current?.emit('update-tickets', [{ ...state.tickets.find(t => t.id === id), calledAt: Date.now() }])}
                onStartAttendance={(id) => socketRef.current?.emit('update-tickets', [{ ...state.tickets.find(t => t.id === id), status: TicketStatus.IN_PROGRESS, startedAt: Date.now() }])}
                onFinishTicket={(id) => socketRef.current?.emit('update-tickets', [{ ...state.tickets.find(t => t.id === id), status: TicketStatus.FINISHED, finishedAt: Date.now() }])}
                onNoShow={(id) => socketRef.current?.emit('update-tickets', [{ ...state.tickets.find(t => t.id === id), status: TicketStatus.NO_SHOW, finishedAt: Date.now() }])}
             />
           )}
           {state.view === 'reports' && <ReportsView tickets={state.tickets} services={state.services} users={state.users} systemInfo={systemInfo} />}
           {state.view === 'settings' && <SettingsView 
              services={state.services} 
              users={state.users} 
              onAddService={(name) => socketRef.current?.emit('update-services', [{ id: uuidv4(), name, active: true }])}
              onUpdateService={(id, name) => socketRef.current?.emit('update-services', [{ id, name, active: true }])}
              onDeleteService={(id) => socketRef.current?.emit('delete-service', id)}
              onAddUser={(u) => socketRef.current?.emit('update-users', [{ id: uuidv4(), ...u, active: true }])}
              onUpdateUser={(id, u) => socketRef.current?.emit('update-users', [{ id, ...u, active: true }])}
              onDeleteUser={(id) => socketRef.current?.emit('delete-user', id)}
              onNavigateHome={() => setState(p => ({...p, view: 'home'}))}
            />}
        </div>
      </main>
    </div>
  );
}

const MenuButton = ({ active, onClick, icon, label }: any) => (
  <button onClick={onClick} className={`w-full flex items-center gap-4 px-5 py-4 rounded-[1.25rem] transition-all group ${active ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' : 'text-slate-500 hover:bg-white/5 hover:text-white'}`}>
    <span className={`${active ? 'text-white' : 'text-slate-600 group-hover:text-indigo-400'} transition-colors`}>{icon}</span>
    <span className="text-sm font-black tracking-tight">{label}</span>
  </button>
);

const StatCard = ({ icon, label, value, trend }: any) => (
  <div className="bg-slate-900/40 border border-white/5 p-7 rounded-[2rem] shadow-xl group hover:border-indigo-500/30 transition-all hover:scale-[1.02]">
    <div className="flex justify-between items-start mb-4">
      <div className="w-12 h-12 rounded-2xl flex items-center justify-center bg-white/5 group-hover:bg-indigo-600/10 transition-colors">{icon}</div>
      <span className="text-[9px] font-black text-emerald-500 bg-emerald-500/5 px-2 py-1 rounded-lg uppercase tracking-tighter">{trend}</span>
    </div>
    <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">{label}</p>
    <p className="text-3xl font-black text-white tracking-tighter">{value}</p>
  </div>
);

const QuickAction = ({ icon, label, desc, color, onClick }: any) => (
  <button onClick={onClick} className={`${color} p-6 rounded-[1.75rem] flex flex-col items-center text-center gap-3 hover:brightness-110 active:scale-[0.98] transition-all shadow-xl shadow-black/20 group`}>
    <div className="bg-white/10 p-3 rounded-2xl text-white group-hover:scale-110 transition-transform">{icon}</div>
    <div>
      <p className="font-black text-white text-sm tracking-tight">{label}</p>
      <p className="text-[10px] text-white/60 font-bold tracking-tight">{desc}</p>
    </div>
  </button>
);

export default App;
